const records = $json.records || [];
const syncRunId = $json.sync_run_id || null;

if (records.length === 0) {
  return [
    {
      json: {
        __empty_batch: true,
        count: 0,
        records: [],
        sync_run_id: syncRunId
      }
    }
  ];
}

return records.map(record => ({
  json: {
    ...record,
    sync_run_id: syncRunId
  }
}));

const syncRunId =
  $json.sync_run_id ??
  $("Postgres Create Sync Run").first().json.sync_run_id ??
  null;

return [
  {
    json: {
      sync_run_id: syncRunId,
      run_status: "success",
      fetched_count: 0,
      staged_count: 0,
      promoted_count: 0,
      skipped_count: 0,
      error_count: 0
    }
  }
];

const allItems = $input.all();

const syncRunItem = allItems.find(i => i.json.sync_run_id !== undefined);
const syncRunId = syncRunItem?.json?.sync_run_id ?? null;

const fetchedCount = Number($("HTTP Request").first().json.count || 0);
const stagedCount = $("Postgres Raw Stag").all().length;

const promotedItems = $("Postgres Promote Final").all();
const promotedCount = promotedItems.filter(item => {
  const j = item.json || {};
  return !!(j.id || j.erp_sync_id || j.po_number);
}).length;

const skippedCount = Math.max(fetchedCount - promotedCount, 0);

return [
  {
    json: {
      sync_run_id: syncRunId,
      run_status: "success",
      fetched_count: fetchedCount,
      staged_count: stagedCount,
      promoted_count: promotedCount,
      skipped_count: skippedCount,
      error_count: 0
    }
  }
];

function getText(val) {
  if (val === null || val === undefined) return null;
  if (typeof val === "object") {
    if ("#text" in val) return val["#text"] === "" ? null : String(val["#text"]).trim();
    return null;
  }
  const s = String(val).trim();
  return s === "" ? null : s;
}

function parseNumberFromMixed(val) {
  const txt = getText(val);
  if (!txt) return null;
  const cleaned = txt.replace(/,/g, "").match(/-?\d+(\.\d+)?/);
  return cleaned ? Number(cleaned[0]) : null;
}

const out = [];

for (const item of $input.all()) {
  const row = item.json;
  const raw = row.raw_payload || {};
  const parentErpSyncId = row.erp_sync_id;
  const syncRunId = row.sync_run_id;

  let lines = raw["ALLINVENTORYENTRIES.LIST"];

  if (!lines) continue;

  if (!Array.isArray(lines)) {
    lines = [lines];
  }

  lines.forEach((line, idx) => {
    const lineNumber = idx + 1;
    const lineErpSyncId = `${parentErpSyncId}:${lineNumber}`;

    const itemDescription = getText(line["STOCKITEMNAME"]);
    const billedQty = parseNumberFromMixed(line["BILLEDQTY"]);
    const actualQty = parseNumberFromMixed(line["ACTUALQTY"]);
    const quantity = billedQty ?? actualQty ?? null;

    const unitPrice = parseNumberFromMixed(line["RATE"]);
    const amountRaw = parseNumberFromMixed(line["AMOUNT"]);
    const totalAmount = amountRaw === null ? null : Math.abs(amountRaw);

    const sourceHash = [
      lineErpSyncId,
      itemDescription ?? "",
      quantity ?? "",
      unitPrice ?? "",
      totalAmount ?? ""
    ].join("|");

    out.push({
      json: {
        sync_run_id: syncRunId,
        erp_sync_id: lineErpSyncId,
        parent_erp_sync_id: String(parentErpSyncId),
        line_number: lineNumber,
        item_description: itemDescription,
        quantity,
        unit_price: unitPrice,
        total_amount: totalAmount,
        source_hash: sourceHash,
        raw_payload: line
      }
    });
  });
}

return out;
